// Extract lead data from the incoming webhook payload
const body = $input.first().json.body || $input.first().json;

const name    = body.name        || 'Unknown';
const phone   = body.phone       || 'N/A';
const email   = body.email       || 'N/A';
const subject = body.subject     || 'N/A';
const source  = body.leadSource  || 'Unknown';

// Format timestamp
const now = new Date();
const time = now.toLocaleString('en-US', {
  timeZone: 'America/New_York',
  month:  'short',
  day:    'numeric',
  hour:   'numeric',
  minute: '2-digit',
  hour12: true,
});

// Build WhatsApp message
const message =
  `*New Lead - Pearl View*\n\n` +
  `*Name:* ${name}\n` +
  `*Phone:* ${phone}\n` +
  `*Email:* ${email}\n` +
  `*Subject:* ${subject}\n` +
  `*Source:* ${source}\n` +
  `*Time:* ${time}\n\n` +
  `Open the dashboard to manage this lead.`;

return [{ json: { message } }];
